# [doc = " Produce a human-readable diff description between `expected` and `actual` (C3/G11)."] # [doc = ""] # [doc = " This is a minimal line-level diff sufficient for the EXPLAIN artifact; a full diff tool"] # [doc = " lives in the runner, not this library."] fn make_diff (expected : & str , actual : & str) -> String { let exp_lines : Vec < & str > = expected . lines () . collect () ; let act_lines : Vec < & str > = actual . lines () . collect () ; let mut result = String :: new () ; let max = exp_lines . len () . max (act_lines . len ()) ; for i in 0 .. max { match (exp_lines . get (i) , act_lines . get (i)) { (Some (e) , Some (a)) if e == a => { result . push_str (& format ! ("  {e}
")) ; } (Some (e) , Some (a)) => { result . push_str (& format ! ("- {e}
+ {a}
")) ; } (Some (e) , None) => { result . push_str (& format ! ("- {e}
")) ; } (None , Some (a)) => { result . push_str (& format ! ("+ {a}
")) ; } (None , None) => { } } } result }
